+		CommitterEmail: "test@example.com",
+		Database:       "testdb",
+	}
+
+	store, err := New(ctx, cfg)
+	if err != nil {
+		os.RemoveAll(tmpDir)
+		t.Fatalf("failed to create Dolt store: %v", err)
+	}
